SCRIPT='try {
  $sid="S-1-5-21-3276480634-3513337142-777477859-1020"
  $name="bujuw_user"
  Write-Output "STEP 1: sid=$sid name=$name"
  $sig=''[DllImport("userenv.dll", SetLastError=true, CharSet=CharSet.Unicode)] public static extern int CreateProfile(string sid, string name, System.Text.StringBuilder path, uint cch);''
  Write-Output "STEP 2: sig defined"
  $t = Add-Type -MemberDefinition $sig -Name UE -Namespace W32 -Using System.Text -PassThru -ErrorAction Stop
  Write-Output "STEP 3: type added"
  $sb = New-Object System.Text.StringBuilder 260
  Write-Output "STEP 4: sb capacity=$($sb.Capacity)"
  $rc = $t::CreateProfile($sid, $name, $sb, [uint32]$sb.Capacity)
  Write-Output "STEP 5: rc=$rc path=$($sb.ToString())"
  if ($rc -eq 0) {
    Write-Output "RESULT: CREATED $($sb.ToString())"
  } elseif ($rc -eq -2147024713) {
    Write-Output "RESULT: EXISTS (already registered)"
  } else {
    Write-Output ("RESULT: ERR rc=$rc hex=0x" + ("{0:X8}" -f $rc))
  }
} catch {
  Write-Output "EXCEPTION TYPE: $($_.Exception.GetType().FullName)"
  Write-Output "EXCEPTION MSG: $($_.Exception.Message)"
  Write-Output "STACK: $($_.ScriptStackTrace)"
}'
ENCODED=$(printf '%s' "$SCRIPT" | iconv -t UTF-16LE | base64 | tr -d '\n')
./tt/buw-jpS.PrivilegedSsh.sh bujn-winpc "powershell -NoProfile -EncodedCommand $ENCODED"

